class Solution:
    def minOperations(self, s1: str, s2: str, x: int) -> int:
        # Step 1: Identify differing positions between s1 and s2
        diff = [i for i in range(len(s1)) if s1[i] != s2[i]]

        # Step 2: Check if the number of differing positions is even
        if len(diff) % 2 != 0:
            return -1

        # Step 3: Use dynamic programming to find the minimum cost
        n = len(diff)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            # Case 1: Use the first operation (cost x) to flip two differing bits
            if i >= 2:
                dp[i] = min(dp[i], dp[i-2] + x)

            # Case 2: Use the second operation (cost 1) to flip adjacent differing bits
            if i >= 2 and abs(diff[i-1] - diff[i-2]) == 1:
                dp[i] = min(dp[i], dp[i-2] + 1)

        return dp[n] if dp[n] != float('inf') else -1
